SELECT user_id, email, password, name, phone, role, status, restrict_until, preferred_location, created_at, updated_at FROM users WHERE 1=1
AND (name LIKE CONCAT('%', #{keyword}, '%') OR email LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%'))
AND status = #{status}
AND role = #{role}
ORDER BY created_at DESC

SELECT COUNT(*)
FROM users
WHERE status = #{status}
